// T209 SubscriptionPlanOrchestrator — integer cents guard at ORDER 1
async orchestratePlanPublish(event: Record<string, unknown>): Promise<DataProcessResult<void>> {
  // ORDER 1: Integer cents guard — MUST be first
  const priceCents = event['priceCents'] as number;
  if (!Number.isInteger(priceCents) || priceCents <= 0) {
    return DataProcessResult.failure('FLOAT_PRICE_REJECTED', 'priceCents must be a positive integer');
  }

  // ORDER 2: SETNX idempotency (only after guard passes)
  const key = hash(tenantId + planId + version);
  const acquired = await this.setnx(key);
  if (!acquired) return DataProcessResult.failure('DUPLICATE', 'Plan already published');

  // ORDER 3-5: OCC read, interval validation, audit store
  // ...

  // ORDER 6: OCC write — NOT plain storeDocument
  const result = await this.db.storeDocumentWithOCC('xiigen-subscription-plans', plan, versionPin);
  if (!result.isSuccess && result.errorCode === 'OCC_CONFLICT') {
    await this.queue.enqueue('SubscriptionPlanPublicationFailed', { planId });
    return DataProcessResult.failure('OCC_CONFLICT', 'Version changed — retry with fresh read');
  }

  // ORDER 7: enqueue AFTER store (DNA-8)
  await this.queue.enqueue('SubscriptionPlanPublished', { planId });
  return DataProcessResult.success(undefined);

// ❌ WRONG: float price not guarded at ORDER 1 = BUILD_FAILURE
// ❌ WRONG: plain storeDocument() at ORDER 6 = BUILD_FAILURE
}
